  // Match (X / C0) * C1 | (X % C0) -> (X / C0) * (C1 - C0) + X
  // This uses the identity: X = (X / C0) * C0 + (X % C0)
  // So: (X / C0) * C1 + (X % C0) = (X / C0) * C1 + X - (X / C0) * C0
  //                                = (X / C0) * (C1 - C0) + X
  // This is valid when the 'or' is disjoint (no common bits).
  {
    Value *DivOpV, *RemOpV;
    const APInt *DivC, *MulC;
    // Match Op0 = (X / C0) * C1 and Op1 = X % C0, or vice versa
    // MatchMul handles both mul and shl (shift left)
    if ((match(Op0, m_UDiv(m_Value(DivOpV), m_APInt(DivC))) &&
         match(Op0, m_Mul(m_Value(), m_APInt(MulC)))) ||
        (match(Op1, m_UDiv(m_Value(DivOpV), m_APInt(DivC))) &&
         match(Op1, m_Mul(m_Value(), m_APInt(MulC))))) {
      // We need to find which operand has the div and which has the rem
      Value *DivSide = nullptr, *RemSide = nullptr;
      if (match(Op0, m_UDiv(m_Value(), m_APInt())) &&
          match(Op0, m_Mul(m_Value(), m_APInt()))) {
        DivSide = Op0;
        RemSide = Op1;
      } else {
        DivSide = Op1;
        RemSide = Op0;
      }
      // Extract the div and mul constants from DivSide
      Value *DivOp;
      const APInt *DivConst, *MulConst;
      if (match(DivSide, m_Mul(m_OneUse(m_UDiv(m_Value(DivOp), m_APInt(DivConst))),
                               m_APInt(MulConst)))) {
        // Check that RemSide = X % C0 where X == DivOp and C0 == DivConst
        Value *RemOp;
        const APInt *RemConst;
        if (match(RemSide, m_URem(m_Value(RemOp), m_APInt(RemConst))) &&
            RemOp == DivOp && *RemConst == *DivConst) {
          // Compute C1 - C0
          APInt Diff = *MulConst - *DivConst;
          // Create (X / C0) * (C1 - C0)
          Value *Div = Builder.CreateUDiv(DivOp, ConstantInt::get(DivOp->getType(), *DivConst));
          Value *Mul = Builder.CreateMul(Div, ConstantInt::get(DivOp->getType(), Diff));
          // Return (X / C0) * (C1 - C0) + X
          return BinaryOperator::CreateAdd(Mul, DivOp);
        }
      }
    }
  }
